#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char s[1005];
    while (T--) {
        if (scanf("%s", s) != 1) break;
        for (int i = 0; s[i] != '\0'; ++i) {
            if ((s[i] >= 'a' && s[i] <= 'z') || (s[i] >= 'A' && s[i] <= 'Z'))
                putchar(s[i]);
        }
        putchar('\n');
    }
    return 0;
}

