const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').split('\n');
let idx = 0;
const T = parseInt(input[idx++], 10);
let results = [];
for (let t = 0; t < T; ++t) {
  const s = input[idx++] ?? '';
  let res = '';
  for (const ch of s) {
    if ((ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z')) {
      res += ch;
    }
  }
  results.push(res);
}
process.stdout.write(results.join('\n'));
